from django.conf import settings
from django.contrib.auth import login
from django.contrib.auth.models import User
from django.http import HttpResponseBadRequest
from django.views import View
from lxml import etree
import base64
import time
from datetime import datetime
from django.utils import timezone

class SAMLResponseView(View):
    def post(self, request):
        saml_response = request.POST.get('SAMLResponse')
        if not saml_response:
            return HttpResponseBadRequest("Missing SAMLResponse")

        saml_response = base64.b64decode(saml_response)
        xml_tree = etree.fromstring(saml_response)

        # Validate XML structure
        if not self.validate_xml(xml_tree):
            return HttpResponseBadRequest("Invalid SAML Response")

        # Extract NameID and attributes
        name_id = self.extract_name_id(xml_tree)
        attributes = self.extract_attributes(xml_tree)

        # Validate timestamp
        if not self.validate_timestamp(xml_tree):
            return HttpResponseBadRequest("SAML Response is expired")

        # Create or get user
        user, created = User.objects.get_or_create(username=name_id)
        for attr, value in attributes.items():
            setattr(user, attr, value)
        user.save()

        # Log in the user
        login(request, user)
        return HttpResponse("User logged in successfully")

    def validate_xml(self, xml_tree):
        # Basic XML structure validation
        return xml_tree.tag == '{urn:oasis:names:tc:SAML:2.0:assertion}Assertion'

    def extract_name_id(self, xml_tree):
        name_id_element = xml_tree.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}NameID')
        return name_id_element.text if name_id_element is not None else None

    def extract_attributes(self, xml_tree):
        attributes = {}
        for attr in xml_tree.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}Attribute'):
            attr_name = attr.get('Name')
            attr_value = attr.find('{urn:oasis:names:tc:SAML:2.0:assertion}AttributeValue').text
            attributes[attr_name] = attr_value
        return attributes

    def validate_timestamp(self, xml_tree):
        issue_instant = xml_tree.get('IssueInstant')
        if issue_instant:
            issue_time = datetime.strptime(issue_instant, '%Y-%m-%dT%H:%M:%SZ')
            current_time = timezone.now()
            return (current_time - issue_time).total_seconds() < 300  # 5 minutes validity
        return False